{"sql":"WITH open_prs AS (
    SELECT repo FROM github_pull_requests WHERE state = 'open'
),
total_count AS (
    SELECT COUNT(*) AS total FROM open_prs
),
repo_counts AS (
    SELECT repo, COUNT(*) AS cnt FROM open_prs GROUP BY repo ORDER BY cnt DESC LIMIT 1
)
SELECT total_count.total, repo_counts.repo, repo_counts.cnt
FROM total_count, repo_counts"}
